<?php
 namespace WPAICG; require_once WPAICG_PLUGIN_DIR . 'includes/class-aipkit-dependency-loader.php'; require_once WPAICG_PLUGIN_DIR . 'includes/class-aipkit-hook-manager.php'; require_once WPAICG_PLUGIN_DIR . 'includes/class-aipkit-module-initializer.php'; require_once WPAICG_PLUGIN_DIR . 'includes/class-aipkit-shared-assets-manager.php'; use WPAICG\Includes\AIPKit_Dependency_Loader; use WPAICG\Includes\AIPKit_Hook_Manager; use WPAICG\Includes\AIPKit_Module_Initializer; use WPAICG\Includes\AIPKit_Shared_Assets_Manager; require_once WPAICG_PLUGIN_DIR . 'includes/class-wp-ai-content-generator-activator.php'; require_once WPAICG_PLUGIN_DIR . 'classes/dashboard/class-aipkit_role_manager.php'; if (!defined('ABSPATH')) { exit; } class WP_AI_Content_Generator { private static $instance = null; private $version; private $plugin_name; public const DB_VERSION_OPTION = 'aipkit_plugin_version'; public const TOKEN_MANAGER_SCHEMA_VERSION_OPTION = 'aipkit_token_manager_schema_version'; public const TOKEN_MANAGER_SCHEMA_VERSION = '3'; private const INSTALL_INTEGRITY_TRANSIENT = 'aipkit_install_integrity_checked'; public static function get_instance(): WP_AI_Content_Generator { if (null === self::$instance) { self::$instance = new self(); } return self::$instance; } private function __construct() { $this->version = defined('WPAICG_VERSION') ? WPAICG_VERSION : '1.9.15'; $this->plugin_name = 'gpt3-ai-content-generator'; } public function run() { AIPKit_Dependency_Loader::load(); add_action('init', [$this, 'register_shared_assets'], 0); add_action('init', [$this, 'check_for_updates'], 10); AIPKit_Hook_Manager::register_hooks($this->version); AIPKit_Module_Initializer::init($this->version); } public function register_shared_assets() { AIPKit_Shared_Assets_Manager::register($this->version); } public function check_for_updates() { if (!$this->should_run_update_check()) { return; } $current_version = $this->version; $saved_version = get_option(self::DB_VERSION_OPTION); $saved_token_manager_schema_version = get_option(self::TOKEN_MANAGER_SCHEMA_VERSION_OPTION); $version_needs_update = version_compare((string) $saved_version, $current_version, '<'); $token_manager_schema_needs_update = version_compare( (string) $saved_token_manager_schema_version, self::TOKEN_MANAGER_SCHEMA_VERSION, '<' ); $tables_are_missing = false; $vector_index_missing = false; if ($version_needs_update || $token_manager_schema_needs_update || $this->should_run_install_integrity_check()) { $tables_are_missing = $this->are_plugin_tables_missing(); $vector_index_missing = $this->is_vector_data_source_index_missing(); } if (!$version_needs_update && !$tables_are_missing && !$vector_index_missing && !$token_manager_schema_needs_update) { set_transient(self::INSTALL_INTEGRITY_TRANSIENT, '1', DAY_IN_SECONDS); return; } delete_transient(self::INSTALL_INTEGRITY_TRANSIENT); $this->clear_external_caches(); WP_AI_Content_Generator_Activator::setup_tables_for_blog(); $this->cleanup_legacy_chatbot_pricing_overrides(); if (class_exists('\\WPAICG\\AIPKit_Role_Manager')) { \WPAICG\AIPKit_Role_Manager::update_permissions_on_activation(); } if (class_exists('\\WPAICG\\Chat\\Storage\\DefaultBotSetup')) { \WPAICG\Chat\Storage\DefaultBotSetup::ensure_default_chatbot(); } if (class_exists('\\WPAICG\\ContentWriter\\AIPKit_Content_Writer_Template_Manager')) { \WPAICG\ContentWriter\AIPKit_Content_Writer_Template_Manager::ensure_default_template_exists(); } if (class_exists('\\WPAICG\\AIForms\\Admin\\AIPKit_AI_Form_Defaults')) { \WPAICG\AIForms\Admin\AIPKit_AI_Form_Defaults::ensure_default_forms_exist(); } if (class_exists('\\WPAICG\\Core\\TokenManager\\AIPKit_Token_Manager')) { \WPAICG\Core\TokenManager\AIPKit_Token_Manager::schedule_token_reset_event(); } if (class_exists('\\WPAICG\\Core\\Stream\\Cache\\AIPKit_SSE_Message_Cache')) { \WPAICG\Core\Stream\Cache\AIPKit_SSE_Message_Cache::schedule_cleanup_event(); } if (class_exists('\\WPAICG\\AutoGPT\\AIPKit_Automated_Task_Cron')) { \WPAICG\AutoGPT\AIPKit_Automated_Task_Cron::init(); } update_option(self::DB_VERSION_OPTION, $current_version, 'no'); update_option(self::TOKEN_MANAGER_SCHEMA_VERSION_OPTION, self::TOKEN_MANAGER_SCHEMA_VERSION, 'no'); set_transient(self::INSTALL_INTEGRITY_TRANSIENT, '1', DAY_IN_SECONDS); } private function should_run_update_check(): bool { if (function_exists('wp_installing') && wp_installing()) { return true; } if (is_admin() || wp_doing_cron()) { return true; } return defined('WP_CLI') && WP_CLI; } private function should_run_install_integrity_check(): bool { return false === get_transient(self::INSTALL_INTEGRITY_TRANSIENT); } private function cleanup_legacy_chatbot_pricing_overrides(): void { global $wpdb; $pricing_rules_table = $wpdb->prefix . 'aipkit_pricing_rules'; $table_exists = $wpdb->get_var($wpdb->prepare("SHOW TABLES LIKE %s", $pricing_rules_table)); if ($table_exists === $pricing_rules_table) { $wpdb->query($wpdb->prepare("DELETE FROM {$pricing_rules_table} WHERE scope_type IN (%s, %s)", 'chatbot', 'bot')); } delete_post_meta_by_key('_aipkit_token_pricing_mode'); } private function are_plugin_tables_missing(): bool { global $wpdb; $required_tables = [ 'aipkit_chat_logs', 'aipkit_guest_token_usage', 'aipkit_sse_message_cache', 'aipkit_vector_data_source', 'aipkit_automated_tasks', 'aipkit_automated_task_queue', 'aipkit_content_writer_templates', 'aipkit_rss_history', 'aipkit_event_delivery_queue', 'aipkit_recipe_delivery_logs', 'aipkit_pricing_rules', 'aipkit_token_ledger', ]; foreach ($required_tables as $table_suffix) { $table_name = $wpdb->prefix . $table_suffix; if ($wpdb->get_var($wpdb->prepare("SHOW TABLES LIKE %s", $table_name)) !== $table_name) { return true; } } return false; } private function is_vector_data_source_index_missing(): bool { global $wpdb; $table_name = $wpdb->prefix . 'aipkit_vector_data_source'; $index_name = 'provider_store_time'; $table_exists = $wpdb->get_var($wpdb->prepare('SHOW TABLES LIKE %s', $table_name)); if ($table_exists !== $table_name) { return false; } $index_rows = $wpdb->get_results($wpdb->prepare("SHOW INDEX FROM {$table_name} WHERE Key_name = %s", $index_name)); return empty($index_rows); } private function clear_external_caches() { if (false === apply_filters('aipkit_auto_clear_caches_on_update', true)) { return; } if (function_exists('rocket_clean_domain')) { rocket_clean_domain(); } wp_cache_flush(); } public function get_plugin_name(): string { return $this->plugin_name; } public function get_version(): string { return $this->version; } } 